export class PostsComponent {
  constructor(svc) {
    this.svc = svc;
    this.allPosts = [];
    this.posts = [];
    this.displayed = [];
    this.toasts = [];
    this.toastCounter = 0;
    this.searchQuery = '';
    this.pageSize = 10;
    this.currentPage = 0;
    this.hasMore = false;
    this.loading = false;
    // Form state
    this.showForm = false;
    this.editingId = null;
    this.formTitle = '';
    this.formBody = '';
    this.formLoading = false;
    this.toastTimers = [];
  }
  ngOnInit() {
    this.loadPosts();
  }
  ngOnDestroy() {
    this.toastTimers.forEach(clearTimeout);
  }
  loadPosts() {
    this.loading = true;
    this.svc.getAll().subscribe({
      next: data => {
        this.allPosts = data;
        this.applySearch();
        this.loading = false;
      },
      error: () => {
        this.toast('Failed to load posts', 'error');
        this.loading = false;
      }
    });
  }
  applySearch() {
    const q = this.searchQuery.toLowerCase().trim();
    this.posts = q ? this.allPosts.filter(p => p.title.toLowerCase().includes(q) || p.body.toLowerCase().includes(q)) : [...this.allPosts];
    this.currentPage = 0;
    this.updateDisplayed();
  }
  updateDisplayed() {
    const end = (this.currentPage + 1) * this.pageSize;
    this.displayed = this.posts.slice(0, end);
    this.hasMore = this.posts.length > end;
  }
  loadMore() {
    this.currentPage++;
    this.updateDisplayed();
  }
  openCreate() {
    this.editingId = null;
    this.formTitle = '';
    this.formBody = '';
    this.showForm = true;
  }
  openEdit(post) {
    this.editingId = post._id;
    this.formTitle = post.title;
    this.formBody = post.body;
    this.showForm = true;
  }
  cancelForm() {
    this.showForm = false;
    this.editingId = null;
  }
  submitForm() {
    if (!this.formTitle.trim() || !this.formBody.trim()) {
      this.toast('Title and body are required', 'error');
      return;
    }
    this.editingId ? this.doUpdate() : this.doCreate();
  }
  doCreate() {
    const tempId = 'temp_' + Date.now();
    const optimistic = {
      _id: tempId,
      title: this.formTitle,
      body: this.formBody,
      userId: 1,
      isNew: true
    };
    this.allPosts.unshift(optimistic);
    this.applySearch();
    this.showForm = false;
    this.formLoading = true;
    this.svc.create({
      title: this.formTitle,
      body: this.formBody
    }).subscribe({
      next: created => {
        const idx = this.allPosts.findIndex(p => p._id === tempId);
        if (idx !== -1) this.allPosts[idx] = {
          ...created,
          isNew: true
        };
        this.applySearch();
        this.formLoading = false;
        this.toast('Post created!', 'success');
      },
      error: () => {
