import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { PostService } from '../../services/post.service';
import { Post } from '../../models/post.model';

interface Toast {
  id: number;
  message: string;
  type: 'success' | 'error';
}

@Component({
  selector: 'app-posts',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './posts.component.html',
  styleUrls: ['./posts.component.css'],
})
export class PostsComponent implements OnInit, OnDestroy {
  allPosts: Post[]      = [];
  posts: Post[]         = [];
  displayed: Post[]     = [];
  toasts: Toast[]       = [];
  toastCounter          = 0;

  searchQuery  = '';
  pageSize     = 10;
  currentPage  = 0;
  hasMore      = false;
  loading      = false;

  // Form state
  showForm     = false;
  editingId: string | null = null;
  formTitle    = '';
  formBody     = '';
  formLoading  = false;

  private toastTimers: ReturnType<typeof setTimeout>[] = [];

  constructor(private svc: PostService) {}

  ngOnInit() { this.loadPosts(); }

  ngOnDestroy() { this.toastTimers.forEach(clearTimeout); }

  loadPosts() {
    this.loading = true;
    this.svc.getAll().subscribe({
      next: (data) => {
        this.allPosts = data;
        this.applySearch();
        this.loading = false;
      },
      error: () => {
        this.toast('Failed to load posts', 'error');
        this.loading = false;
      },
    });
  }

  applySearch() {
    const q = this.searchQuery.toLowerCase().trim();
    this.posts = q
      ? this.allPosts.filter(
          (p) =>
            p.title.toLowerCase().includes(q) ||
            p.body.toLowerCase().includes(q)
        )
      : [...this.allPosts];
    this.currentPage = 0;
    this.updateDisplayed();
  }

  updateDisplayed() {
    const end = (this.currentPage + 1) * this.pageSize;
    this.displayed = this.posts.slice(0, end);
    this.hasMore   = this.posts.length > end;
  }

  loadMore() {
    this.currentPage++;
    this.updateDisplayed();
  }

  openCreate() {
    this.editingId  = null;
    this.formTitle  = '';
    this.formBody   = '';
    this.showForm   = true;
  }

  openEdit(post: Post) {
    this.editingId  = post._id!;
    this.formTitle  = post.title;
    this.formBody   = post.body;
    this.showForm   = true;
  }

  cancelForm() {
    this.showForm = false;
    this.editingId = null;
  }

  submitForm() {
    if (!this.formTitle.trim() || !this.formBody.trim()) {
      this.toast('Title and body are required', 'error');
      return;
    }
    this.editingId ? this.doUpdate() : this.doCreate();
  }

  private doCreate() {
    const tempId = 'temp_' + Date.now();
    const optimistic: Post = {
      _id: tempId,
      title: this.formTitle,
      body: this.formBody,
      userId: 1,
      isNew: true,
    };
    this.allPosts.unshift(optimistic);
    this.applySearch();
    this.showForm   = false;
    this.formLoading = true;

    this.svc.create({ title: this.formTitle, body: this.formBody }).subscribe({
      next: (created) => {
        const idx = this.allPosts.findIndex((p) => p._id === tempId);
        if (idx !== -1) this.allPosts[idx] = { ...created, isNew: true };
        this.applySearch();
        this.formLoading = false;
        this.toast('Post created!', 'success');
      },
      error: () => {
        this.allPosts = this.allPosts.filter((p) => p._id !== tempId);
        this.applySearch();
        this.formLoading = false;
        this.toast('Failed to create post', 'error');
      },
    });
  }

  private doUpdate() {
    const id = this.editingId!;
    const prev = this.allPosts.find((p) => p._id === id);
    const snapshot = prev ? { ...prev } : null;

    const idx = this.allPosts.findIndex((p) => p._id === id);
    if (idx !== -1) {
      this.allPosts[idx] = {
        ...this.allPosts[idx],
        title: this.formTitle,
        body: this.formBody,
        isUpdated: true,
        isNew: false,
      };
    }
    this.applySearch();
    this.showForm    = false;
    this.formLoading = true;

    this.svc.update(id, { title: this.formTitle, body: this.formBody }).subscribe({
      next: (updated) => {
        const i = this.allPosts.findIndex((p) => p._id === id);
        if (i !== -1) this.allPosts[i] = { ...updated, isUpdated: true };
        this.applySearch();
        this.formLoading = false;
        this.toast('Post updated!', 'success');
      },
      error: () => {
        if (snapshot) {
          const i = this.allPosts.findIndex((p) => p._id === id);
          if (i !== -1) this.allPosts[i] = snapshot;
          this.applySearch();
        }
        this.formLoading = false;
        this.toast('Failed to update post', 'error');
      },
    });
  }

  deletePost(post: Post) {
    const id      = post._id!;
    const backup  = [...this.allPosts];

    this.allPosts = this.allPosts.filter((p) => p._id !== id);
    this.applySearch();

    this.svc.delete(id).subscribe({
      next: () => this.toast('Post deleted', 'success'),
      error: () => {
        this.allPosts = backup;
        this.applySearch();
        this.toast('Failed to delete post', 'error');
      },
    });
  }

  toast(message: string, type: 'success' | 'error') {
    const id = ++this.toastCounter;
    this.toasts.push({ id, message, type });
    const t = setTimeout(() => this.removeToast(id), 3500);
    this.toastTimers.push(t);
  }

  removeToast(id: number) {
    this.toasts = this.toasts.filter((t) => t.id !== id);
  }

  trackByPost(_: number, post: Post) { return post._id; }
  trackByToast(_: number, t: Toast)  { return t.id; }
}
<div class="shell">

  <!-- ── Newspaper Masthead ── -->
  <div class="newspaper-header">
    <div class="masthead">
      <h1 class="newspaper-title">THE DAILY POST</h1>
      <p class="tagline">Your Source for News & Stories</p>
      <p class="date">{{ today | date:'EEEE, MMMM d, y' }}</p>
    </div>
  </div>

  <!-- ── Navigation Bar ── -->
  <header class="header">
    <div class="header-left">
      <button class="btn-new" (click)="openCreate()">
        <span class="btn-plus">+</span> Publish
      </button>
    </div>
    <div class="search-wrap">
      <span class="search-icon">🔍</span>
      <input
        class="search-input"
        type="text"
        placeholder="Search articles…"
        [(ngModel)]="searchQuery"
        (ngModelChange)="applySearch()"
      />
      @if (searchQuery) {
        <button class="search-clear" (click)="searchQuery=''; applySearch()">×</button>
      }
    </div>
    <span class="post-count">{{ posts.length }} article{{ posts.length !== 1 ? 's' : '' }}</span>
  </header>

  <!-- ── Toast Notifications ── -->
  <div class="toast-container">
    @for (t of toasts; track trackByToast($index, t)) {
      <div class="toast" [class.toast-success]="t.type==='success'" [class.toast-error]="t.type==='error'">
        <span class="toast-icon">{{ t.type === 'success' ? '✓' : '✕' }}</span>
        {{ t.message }}
        <button class="toast-close" (click)="removeToast(t.id)">×</button>
      </div>
    }
  </div>

  <!-- ── Create / Edit Form Modal ── -->
  @if (showForm) {
    <div class="modal-backdrop" (click)="cancelForm()">
      <div class="modal" (click)="$event.stopPropagation()">
        <div class="modal-header">
          <h2 class="modal-title">{{ editingId ? 'Edit Article' : 'Write New Article' }}</h2>
          <button class="modal-close" (click)="cancelForm()">×</button>
        </div>
        <div class="modal-body">
          <label class="field-label">Headline</label>
          <input
            class="field-input"
            type="text"
            placeholder="Article headline…"
            [(ngModel)]="formTitle"
          />
          <label class="field-label">Story</label>
          <textarea
            class="field-textarea"
            placeholder="Write your story content…"
            [(ngModel)]="formBody"
            rows="8"
          ></textarea>
        </div>
        <div class="modal-footer">
          <button class="btn-cancel" (click)="cancelForm()">Discard</button>
          <button class="btn-submit" (click)="submitForm()" [disabled]="formLoading">
            @if (formLoading) { <span class="spinner"></span> }
            {{ editingId ? 'Update' : 'Publish' }}
          </button>
        </div>
      </div>
    </div>
  }

  <!-- ── Loading ── -->
  @if (loading) {
    <div class="loading-grid">
      @for (i of [1,2,3,4,5,6]; track i) {
        <div class="skeleton-card">
          <div class="sk sk-title"></div>
          <div class="sk sk-body"></div>
          <div class="sk sk-body short"></div>
          <div class="sk sk-meta"></div>
        </div>
      }
    </div>
  }

  <!-- ── Posts Grid ── -->
  @if (!loading) {
    @if (displayed.length === 0) {
      <div class="empty-state">
        <div class="empty-icon">📰</div>
        <p class="empty-title">No Articles</p>
        <p class="empty-sub">{{ searchQuery ? 'Try a different search term' : 'Start by publishing your first article' }}</p>
        @if (!searchQuery) {
          <button class="btn-new" style="margin-top:2rem" (click)="openCreate()">+ Publish Article</button>
        }
      </div>
    } @else {
      <div class="posts-grid">
        <!-- Featured Article -->
        @if (displayed.length > 0) {
          <article class="post-card post-featured">
            <div class="featured-label">FEATURED</div>
            <div class="post-card-top">
              <div class="badges">
                @if (displayed[0].isNew) {
                  <span class="badge badge-new">NEW</span>
                }
              </div>
              <div class="post-actions">
                <button class="icon-btn edit-btn" title="Edit" (click)="openEdit(displayed[0])">✎</button>
                <button class="icon-btn del-btn"  title="Delete" (click)="deletePost(displayed[0])">⌫</button>
              </div>
            </div>
            <h2 class="post-title featured-title">{{ displayed[0].title }}</h2>
            <p class="post-body featured-body">{{ displayed[0].body }}</p>
            <div class="post-meta">
              @if (displayed[0].createdAt) {
                <span class="meta-date">{{ displayed[0].createdAt | date:'MMM d, y' }}</span>
              }
              <span class="meta-id">By Editor</span>
            </div>
          </article>
        }

        <!-- Other Articles -->
        @if (displayed.length > 1) {
          @for (post of displayed.slice(1); track trackByPost($index + 1, post)) {
            <article class="post-card">
              <div class="post-card-top">
                <div class="badges">
                  @if (post.isNew) {
                    <span class="badge badge-new">NEW</span>
                  }
                  @if (post.isUpdated) {
                    <span class="badge badge-updated">UPDATED</span>
                  }
                </div>
                <div class="post-actions">
                  <button class="icon-btn edit-btn" title="Edit" (click)="openEdit(post)">✎</button>
                  <button class="icon-btn del-btn"  title="Delete" (click)="deletePost(post)">⌫</button>
                </div>
              </div>
              <h3 class="post-title">{{ post.title }}</h3>
              <p class="post-body">{{ post.body }}</p>
              <div class="post-meta">
                <span class="meta-category">STORY</span>
                @if (post.createdAt) {
                  <span class="meta-date">{{ post.createdAt | date:'MMM d' }}</span>
                }
              </div>
            </article>
          }
        }
      </div>

      @if (hasMore) {
        <div class="load-more-row">
          <button class="btn-load-more" (click)="loadMore()">
            LOAD MORE ARTICLES <span class="load-arrow">↓</span>
          </button>
          <span class="load-hint">{{ displayed.length }} of {{ posts.length }}</span>
        </div>
      }
    }
  }

</div>
